args.sparql:
SELECT ?closureDate WHERE { 
  ?ride wdt:P31 wd:Q1412219; 
        rdfs:label 'Log Flume'@en; 
        wdt:P131 wd:Q443909; 
        wdt:P576 ?closureDate. 
}

SELECT ?closureDate WHERE {
  ?ride wdt:P31 wd:Q1412219;  
        rdfs:label 'Log Flume'@en; 
        wdt:P361 wd:Q443909; 
        wdt:P576 ?closureDate.
}

SELECT ?closureDate WHERE {
  wd:Q443909 wdt:P527 ?ride ;
              wdt:P31 wd:Q443909 ;
              rdfs:label 'Alton Towers'@en .
  ?ride wdt:P31 wd:Q1412219 ;
        rdfs:label 'Log Flume'@en ;
        wdt:P576 ?closureDate .
}

SELECT ?closureDate WHERE {
  wd:Q443909 wdt:P527 ?ride .
  ?ride rdfs:label 'Log Flume'@en .
  ?ride wdt:P576 ?closureDate .
}

SELECT ?ride ?label WHERE {
  wd:Q443909 wdt:P527 ?ride .
  ?ride rdfs:label ?label .
  FILTER (LANG(?label) = 'en') .
  FILTER (CONTAINS(LCASE(?label), 'log flume')) .
}

